import java.lang.reflect.Field;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private PrintWriter originalOut;

    @BeforeEach
    void setUp() {
        // CSVPrinter stores a PrintWriter wrapping System.out, so we keep a reference for comparison
        originalOut = new PrintWriter(System.out, true);
    }

    @AfterEach
    void tearDown() {
        // No system out replacement done, so nothing to restore
    }

    @Test
    void testPrinterReturnsCSVPrinterWithSystemOut() throws IOException {
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        CSVPrinter printer = csvFormat.printer();
        assertNotNull(printer);
        assertEquals(CSVPrinter.class, printer.getClass());

        try {
            Field outField = CSVPrinter.class.getDeclaredField("out");
            outField.setAccessible(true);
            Object out = outField.get(printer);
            assertNotNull(out);
            // The 'out' field is a PrintWriter wrapping System.out, so unwrap and compare the underlying OutputStream if possible
            // Since we can't easily unwrap PrintWriter's underlying stream, just check it's a PrintWriter instance
            assertTrue(out instanceof PrintWriter);
        } catch (NoSuchFieldException e) {
            fail("CSVPrinter.out field not found");
        } catch (IllegalAccessException e) {
            fail("Cannot access CSVPrinter.out field");
        }
    }
}
